function createPR(targetRepo, branch, cwd, onLine) {
	const body = [
		"## đź¦… ContentHawk Installation",
		"",
		"This pull request installs [ContentHawk](https://github.com/SSWConsulting/SSW.ContentHawk) into this repository.",
		"",
		"### What's included",
		"- `.github/workflows/` â€” ContentHawk GitHub Actions workflows",
		"- `.github/actions/guard-open-pr/` â€” supporting composite action",
		"- `.contenthawk-version` â€” pinned ContentHawk version for this repo",
		"",
		"### Source",
		"Files were copied from [SSWConsulting/SSW.ContentHawk](https://github.com/SSWConsulting/SSW.ContentHawk) and compiled with `gh aw compile`.",
		"",
		"### Next steps",
		"Review the changes, then merge to enable ContentHawk on this repo."
	].join("\n");
	return new Promise((resolve, reject) => {
		const child = (0, node_child_process.spawn)("gh", [
			"pr",
			"create",
			"--title",
			"đź¦… Installing ContentHawk",
			"--body",
			body,
			"--repo",
			targetRepo
		], { cwd });
		child.stdout.on("data", (d) => String(d).split("\n").filter(Boolean).forEach(onLine));
		child.stderr.on("data", (d) => String(d).split("\n").filter(Boolean).forEach(onLine));
		child.on("error", reject);
		child.on("close", (code) => code === 0 ? resolve() : reject(/* @__PURE__ */ new Error(`gh pr create exited ${code}`)));
	});
}
function die(msg, code = 1) {
	console.error(`ERROR: ${msg}`);
	process.exit(code);
}
function checkGh() {
	const v = (0, node_child_process.spawnSync)("gh", ["--version"]);
	if (v.error || v.status !== 0) die("'gh' CLI is not installed. Install from https://cli.github.com");
	if ((0, node_child_process.spawnSync)("gh", ["auth", "status"]).status !== 0) die("'gh' is not authenticated. Run 'gh auth login' first.");
}
function getExistingSecrets(targetRepo) {
	const result = (0, node_child_process.spawnSync)("gh", [
		"secret",
		"list",
		"--repo",
		targetRepo,
		"--json",
		"name"
	], { encoding: "utf-8" });
	if (result.status !== 0) return /* @__PURE__ */ new Set();
	try {
		const list = JSON.parse(result.stdout);
		return new Set(list.map((s) => s.name));
	} catch {
		return /* @__PURE__ */ new Set();
	}
}
function setSecret(targetRepo, name, value) {
	if (!value.trim()) return Promise.resolve("skipped");
	return new Promise((resolve) => {
		const child = (0, node_child_process.spawn)("gh", [
			"secret",
			"set",
			name,
			"--repo",
			targetRepo,
			"--body",
			value
		]);
		let stderr = "";
		child.stderr.on("data", (d) => stderr += String(d));
		child.on("error", (err) => resolve({ error: err.message }));
		child.on("close", (code) => {
			if (code === 0) resolve("ok");
			else resolve({ error: stderr.trim().split("\n").pop() || `exit ${code}` });
		});
		child.stdin.end();
	});
}
function openBrowser(url) {
	const cmd = process.platform === "darwin" ? "open" : process.platform === "win32" ? "start" : "xdg-open";
	try {
		(0, node_child_process.spawn)(cmd, [url], {
			detached: true,
			stdio: "ignore"
		}).unref();
	} catch {}
}
async function main() {
	const targetRepo = process.argv[2];
	if (!targetRepo || !targetRepo.includes("/") || targetRepo.startsWith("/") || targetRepo.endsWith("/")) die("Usage: install.ts <owner/repo>");
	checkGh();
	const [clientBundle, css] = await Promise.all([bundleClient(), buildCSS()]);
	const token = node_crypto.default.randomBytes(24).toString("base64url");
	let results;
	const done = new Promise((r) => r);
	const server = node_http.default.createServer(async (req, res) => {
		const url = new URL(req.url, `http://${req.headers.host}`);
		if (req.method === "GET" && url.pathname === "/") {
			res.writeHead(200, {
				"Content-Type": "text/html; charset=utf-8",
				"Cache-Control": "no-store"
			});
			return res.end(renderForm(targetRepo, token, css));
		}
		if (req.method === "POST" && url.pathname === "/kill") process.exit(0);
		if (req.method === "GET" && url.pathname === "/bundle.js") {
			res.writeHead(200, {
				"Content-Type": "application/javascript",
				"Cache-Control": "no-store"
			});
			return res.end(clientBundle);
		}
		if (req.method === "GET" && url.pathname === "/existing-secrets") {
			const existing = getExistingSecrets(targetRepo);
			res.writeHead(200, {
				"Content-Type": "application/json",
				"Cache-Control": "no-store"
			});
			return res.end(JSON.stringify({ existing: [...existing] }));
		}
		if (req.method === "GET" && url.pathname === "/branch-status") {
			res.writeHead(200, {
				"Content-Type": "application/json",
				"Cache-Control": "no-store"
			});
			return res.end(JSON.stringify({ exists: checkBranchExists(targetRepo) }));
		}
		if (req.method === "GET" && url.pathname === "/workflow-stream") {
			res.writeHead(200, {
				"Content-Type": "text/event-stream",
				"Cache-Control": "no-cache",
				"Connection": "keep-alive"
			});
			res.flushHeaders();
			const send = (event) => res.write(`data: ${JSON.stringify(event)}\n\n`);
			const log = (message) => send({
				type: "log",
				message
			});
			const sendLine = (line) => /^https?:\/\//.test(line) ? send({
				type: "link",
				message: line,
				url: line
			}) : log(line);
			const tmpDir = await node_fs_promises.default.mkdtemp(node_path.default.join(node_os.default.tmpdir(), "install-"));
			const contentHawkDir = node_path.default.join(tmpDir, "contenthawk");
			const targetDir = node_path.default.join(tmpDir, "target");
			try {
				if (url.searchParams.get("restart") === "true") {
					log("Closing existing PRsâ€¦");
					await closePRsForBranch(targetRepo, sendLine);
					await deleteBranch(targetRepo, sendLine);
				}
				log("Cloning SSWConsulting/SSW.ContentHawkâ€¦");
				await sparseClone("SSWConsulting/SSW.ContentHawk", contentHawkDir, [
					".github/workflows",
					".github/actions/guard-open-pr",
					".contenthawk-version"
				], sendLine);
				log(`Cloning ${targetRepo}â€¦`);
				await sparseClone(targetRepo, targetDir, [".github"], sendLine);
				log("Copying .github/workflowsâ€¦");
				const src = node_path.default.join(contentHawkDir, ".github", "workflows");
				const dest = node_path.default.join(targetDir, ".github", "workflows");
				await node_fs_promises.default.mkdir(dest, { recursive: true });
				for (const file of await node_fs_promises.default.readdir(src)) {
					await node_fs_promises.default.copyFile(node_path.default.join(src, file), node_path.default.join(dest, file));
					log(`  Copied ${file}`);
				}
				log("Copying .github/actions/guard-open-pr/action.ymlâ€¦");
				const actionSrc = node_path.default.join(contentHawkDir, ".github", "actions", "guard-open-pr", "action.yml");
				const actionDest = node_path.default.join(targetDir, ".github", "actions", "guard-open-pr", "action.yml");
				await node_fs_promises.default.mkdir(node_path.default.dirname(actionDest), { recursive: true });
				await node_fs_promises.default.copyFile(actionSrc, actionDest);
				log("  Copied action.yml");
				log("Copying .contenthawk-versionâ€¦");
				await node_fs_promises.default.copyFile(node_path.default.join(contentHawkDir, ".contenthawk-version"), node_path.default.join(targetDir, ".contenthawk-version"));
				log("  Copied .contenthawk-version");
				log("Running gh aw compileâ€¦");
				await compileWorkflows(targetDir, sendLine);
				log(`Creating branch ${CONTENTHAWK_INSTALL_BRANCH}â€¦`);
				await gitRun([
					"checkout",
					"-b",
					CONTENTHAWK_INSTALL_BRANCH
				], targetDir, sendLine);
				log("Staging changesâ€¦");
				await gitRun([
					"add",
					".github/",
					".contenthawk-version"
				], targetDir, sendLine);
				log("Committingâ€¦");
				await gitRun([
					"commit",
					"-m",
					"Add ContentHawk GitHub Actions workflows"
				], targetDir, sendLine);
				log("Pushingâ€¦");
				await gitRun([
					"push",
					"-u",
					"origin",
					CONTENTHAWK_INSTALL_BRANCH
				], targetDir, sendLine);
				log("Creating pull requestâ€¦");
				await createPR(targetRepo, CONTENTHAWK_INSTALL_BRANCH, targetDir, sendLine);
				res.write("event: done\ndata: {}\n\n");
			} catch (err) {
				res.write(`event: failed\ndata: ${JSON.stringify(err instanceof Error ? err.message : String(err))}\n\n`);
			} finally {
				res.end();
				await node_fs_promises.default.rm(tmpDir, {
					recursive: true,
					force: true
				}).catch(() => {});
			}
			return;
		}
		if (req.method === "POST" && url.pathname === "/submit") {
			const chunks = [];
			for await (const chunk of req) chunks.push(chunk);
			const form = new URLSearchParams(Buffer.concat(chunks).toString("utf-8"));
			console.error("FORM_SUBMITTED");
			const existingSecrets = getExistingSecrets(targetRepo);
			const next = {};
			for (const name of SECRETS) {
				const value = form.get(name) ?? "";
				if (!value.trim() && existingSecrets.has(name)) next[name] = "ok";
				else {
					console.log(`Setting secret ${name}â€¦`);
					next[name] = await setSecret(targetRepo, name, value);
				}
			}
			results = next;
			res.writeHead(200, {
				"Content-Type": "application/json; charset=utf-8",
				"Cache-Control": "no-store"
			});
			res.end(JSON.stringify({ results }));
			return;
		}
		res.statusCode = 404;
		res.end();
	});
	await new Promise((r) => server.listen(0, "127.0.0.1", r));
	const addr = server.address();
	if (typeof addr === "string" || !addr) die("Failed to bind server");
	const url = `http://127.0.0.1:${addr.port}/?token=${encodeURIComponent(token)}`;
	console.error(`Open ${url} in your browser to enter secrets.`);
	openBrowser(url);
	await done;
	server.close();
	if (!results) die("No submission received.");
	const ok = SECRETS.filter((n) => results[n] === "ok");
	const skipped = SECRETS.filter((n) => results[n] === "skipped");
	const failed = SECRETS.filter((n) => typeof results[n] === "object");
	if (ok.length) console.log(`Set: ${ok.join(", ")}`);
	if (skipped.length) console.log(`Skipped (empty): ${skipped.join(", ")}`);
	if (failed.length) {
		const detail = failed.map((n) => `${n} (${results[n].error})`).join("; ");
		console.error(`Failed: ${detail}`);
		process.exit(1);
	}
}
main().catch((e) => die(e instanceof Error ? e.message : String(e)));
